.root {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.gallery-stack__img-wrap {
    display: grid;
}

.gallery-stack__img {
    grid-row-start: 1;
    grid-row-end: 1;
    grid-column-start: 1;
    grid-column-end: 1;
}

.gallery-stack__title {
    font-size: 1.5rem;
    line-height: 1.45;
    font-weight: 500;
}
